use std::str;

struct SequenceRecord {
    id: String,
    sequence: Vec<u8>,
}

fn process_records(records: Vec<SequenceRecord>) -> (usize, Option<String>) {
    if records.is_empty() {
        return (0, None);
    }

    let count = records.len();
    let last_record = records.last().unwrap();
    let last_id = str::from_utf8(last_record.id.as_bytes()).unwrap_or("Unknown ID");

    (count, Some(last_id.to_string()))
}

fn main() {
    let mut records = Vec::new();
    records.push(SequenceRecord { id: String::from_utf8(b"SeqA".to_vec()).unwrap(), sequence: vec![1] });
    records.push(SequenceRecord { id: String::from_utf8(b"SeqB".to_vec()).unwrap(), sequence: vec![2] });
    records.push(SequenceRecord { id: String::from_utf8(b"SeqC".to_vec()).unwrap(), sequence: vec![3] });

    let (count, last_id) = process_records(records);

    println!("Total count processed: {}", count);
    match last_id {
        Some(id) => println!("Successfully found the final record ID: {}", id),
        None => println!("No records were provided.")
    }
}

use std::collections::BTreeSet;
use std::hash::{Hash, Hasher};

struct Point {
    x: i32,
    y: i32,
}

impl PartialEq for Point {
    fn eq(&self, other: &Self) -> bool {
        self.x == other.x && self.y == other.y
    }
}

impl Eq for Point {}

impl Hash for Point {
    fn hash<H: Hasher>(&self, state: &mut H) {
        self.x.hash(state);
        self.y.hash(state);
    }
}

impl PartialOrd for Point {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for Point {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        match self.x.cmp(&other.x) {
            std::cmp::Ordering::Equal => self.y.cmp(&other.y),
            other => other,
        }
    }
}

fn main() {
    let mut points = BTreeSet::new();
    points.insert(Point { x: 10, y: 20 });
    points.insert(Point { x: 5, y: 80 });
    points.insert(Point { x: 30, y: 60 });
    points.insert(Point { x: 15, y: 90 });
    points.insert(Point { x: 25, y: 10 });

    let search_box_min_x = 0;
    let search_box_max_x = 40;
    let search_box_min_y = 0;
    let search_box_max_y = 100;

    let count: usize = points.iter()
        .filter(|p| {
            p.x >= search_box_min_x && p.x <= search_box_max_x &&
            p.y >= search_box_min_y && p.y <= search_box_max_y
        })
        .count();

    let last_point: Option<&Point> = points.iter()
        .filter(|p| {
            p.x >= search_box_min_x && p.x <= search_box_max_x &&
            p.y >= search_box_min_y && p.y <= search_box_max_y
        })
        .last();

    println!("Total points found: {}", count);
    match last_point { 
        Some(p) => println!("Last point checked was: ({}, {})", p.x, p.y), 
        None => println!("No points found in the search area."), 
    }
}

use std::time::Duration;

struct DeliveryAttempt {
    delivery_id: String,
    attempt_count: u32,
}

fn process_failed_deliveries(failures: Vec<DeliveryAttempt>) -> (u32, Option<DeliveryAttempt>)
{
    let mut count = 0;
    let mut last_successful: Option<DeliveryAttempt> = None;

    for item in failures.into_iter()
    {
        count += 1;
        if item.attempt_count >= 3
        {
            break;
        }
        last_successful = Some(item);
    }

    (count, last_successful)
}

