use std::collections::VecDeque;
use std::time::{Duration, Instant};

struct RequestRateLimiter {
    window_size: usize,
    request_timestamps: VecDeque<Instant>,
}

impl RequestRateLimiter {
    fn new(window_size: usize) -> Self {
        RequestRateLimiter {
            window_size,
            request_timestamps: VecDeque::new(),
        }
    }

    fn record_and_check(&mut self, now: Instant) -> Result<String, String> {
        self.request_timestamps.push_back(now);

        while self.request_timestamps.len() > self.window_size {
            self.request_timestamps.pop_front();
        }

        let count = self.request_timestamps.len();

        if count == 0 {
            return Err(String::from("No requests recorded."));
        }

        let _last_timestamp = self.request_timestamps.back().unwrap().elapsed().as_secs_f32();
        let status = if count > self.window_size
            .min(10)
        {
            format!("Rate limited: {} requests detected in the window.", count)
        }
        else
        {
            format!("OK: {} requests processed successfully.", count)
        };

        Ok(status)
    }
}

fn main() {
    let mut limiter = RequestRateLimiter::new(3);
    let start_time = Instant::now();

    let result1 = limiter.record_and_check(start_time).unwrap();
    println!("Check 1: {}", result1);

    std::thread::sleep(Duration::from_millis(50));

    let result2 = limiter.record_and_check(Instant::now()).unwrap();
    println!("Check 2: {}", result2);

    std::thread::sleep(Duration::from_millis(50));

    let result3 = limiter.record_and_check(Instant::now()).unwrap();
    println!("Check 3: {}", result3);

    std::thread::sleep(Duration::from_millis(50));

    let result4 = limiter.record_and_check(Instant::now()).unwrap();
    println!("Check 4: {}", result4);
}
